static std::optional<APInt> computeConstantResult(BinaryOperator &BO) {
  auto *C1 = dyn_cast<ConstantInt>(BO.getOperand(0));
  auto *C2 = dyn_cast<ConstantInt>(BO.getOperand(1));
  if (!C1 || !C2)
    return std::nullopt;

  APInt V1 = C1->getValue();
  APInt V2 = C2->getValue();

  switch (BO.getOpcode()) {
  case Instruction::Add:
    return V1 + V2;
  case Instruction::Sub:
    return V1 - V2;
  case Instruction::Mul:
    return V1 * V2;
  case Instruction::SDiv:
    if (V2.isZero())
      return std::nullopt;
    return V1.sdiv(V2);
  case Instruction::UDiv:
    if (V2.isZero())
      return std::nullopt;
    return V1.udiv(V2);
  case Instruction::Shl:
    return V1.shl(V2);
  case Instruction::LShr:
    return V1.lshr(V2);
  case Instruction::AShr:
    return V1.ashr(V2);
  case Instruction::And:
    return V1 & V2;
  case Instruction::Or:
    return V1 | V2;
  case Instruction::Xor:
    return V1 ^ V2;
  default:
    return std::nullopt;
  }
}

bool myConstantPropagation(Function &Foo) {
  bool Changed = false;

  for (BasicBlock &BB : Foo) {
    for (auto &I : llvm::make_early_inc_range(BB)) {
      if (!isa<BinaryOperator>(I))
        continue;

      auto &BO = cast<BinaryOperator>(I);
      std::optional<APInt> Result = computeConstantResult(BO);
      if (!Result.has_value())
        continue;

      ConstantInt *NewConst = ConstantInt::get(BO.getContext(), *Result);
      BO.replaceAllUsesWith(NewConst);
      BO.eraseFromParent();
      Changed = true;
    }
  }

  return Changed;
}
